function calculate(inputs) {
    const { dailyStreamingHours, cloudStorageGB, numberOfLaptops, averageLaptopLifespanYears, numberOfSmartphones, averageSmartphoneLifespanYears, dailyInternetBrowsingHours, weeklyVideoCallHours, weeklyGamingHours } = inputs;

    // Emission Factors (kg CO2e per unit per year, unless specified for manufacturing)
    const EF_STREAMING_HOUR_KGCO2E = 0.05; // Average for various resolutions/platforms
    const EF_CLOUD_STORAGE_GB_YR_KGCO2E = 0.0005; // Represents energy for storage/cooling/data transfer
    const EF_LAPTOP_MANUFACTURING_KGCO2E = 200; // Average for manufacturing, distribution, initial use
    const EF_SMARTPHONE_MANUFACTURING_KGCO2E = 55; // Average for manufacturing, distribution, initial use
    const EF_INTERNET_BROWSING_HOUR_KGCO2E = 0.008; // General browsing, social media, light data use
    const EF_VIDEO_CALL_HOUR_KGCO2E = 0.12; // Higher intensity due to real-time, bidirectional data
    const EF_GAMING_HOUR_KGCO2E = 0.30; // High processing power and network usage

    const DAYS_IN_YEAR = 365;
    const WEEKS_IN_YEAR = 52;

    // Input validation and clamping to prevent absurd results
    const safeDailyStreamingHours = Math.max(0, Math.min(24, dailyStreamingHours || 0));
    const safeCloudStorageGB = Math.max(0, cloudStorageGB || 0);
    const safeNumberOfLaptops = Math.max(0, numberOfLaptops || 0);
    const safeAverageLaptopLifespanYears = Math.max(0.1, averageLaptopLifespanYears || 0.1); // Prevent division by zero
    const safeNumberOfSmartphones = Math.max(0, numberOfSmartphones || 0);
    const safeAverageSmartphoneLifespanYears = Math.max(0.1, averageSmartphoneLifespanYears || 0.1); // Prevent division by zero
    const safeDailyInternetBrowsingHours = Math.max(0, Math.min(24, dailyInternetBrowsingHours || 0));
    const safeWeeklyVideoCallHours = Math.max(0, Math.min(168, weeklyVideoCallHours || 0)); // Max 24*7
    const safeWeeklyGamingHours = Math.max(0, Math.min(168, weeklyGamingHours || 0)); // Max 24*7

    let streamingCarbon = 0;
    let cloudCarbon = 0;
    let deviceCarbon = 0;
    let internetCarbon = 0;
    let videoCallCarbon = 0;
    let gamingCarbon = 0;
    let totalCarbonFootprint = 0;

    // 1. Streaming Emissions
    streamingCarbon = safeDailyStreamingHours * DAYS_IN_YEAR * EF_STREAMING_HOUR_KGCO2E;

    // 2. Cloud Storage Emissions
    cloudCarbon = safeCloudStorageGB * EF_CLOUD_STORAGE_GB_YR_KGCO2E;

    // 3. Device Lifecycle Emissions (Amortized Annually)
    const laptopCarbonAnnual = safeNumberOfLaptops * (EF_LAPTOP_MANUFACTURING_KGCO2E / safeAverageLaptopLifespanYears);
    const smartphoneCarbonAnnual = safeNumberOfSmartphones * (EF_SMARTPHONE_MANUFACTURING_KGCO2E / safeAverageSmartphoneLifespanYears);
    deviceCarbon = laptopCarbonAnnual + smartphoneCarbonAnnual;

    // 4. Internet Browsing & Social Media Emissions
    internetCarbon = safeDailyInternetBrowsingHours * DAYS_IN_YEAR * EF_INTERNET_BROWSING_HOUR_KGCO2E;

    // 5. Video Call Emissions
    videoCallCarbon = safeWeeklyVideoCallHours * WEEKS_IN_YEAR * EF_VIDEO_CALL_HOUR_KGCO2E;

    // 6. Online Gaming Emissions
    gamingCarbon = safeWeeklyGamingHours * WEEKS_IN_YEAR * EF_GAMING_HOUR_KGCO2E;

    // Total Digital Carbon Footprint
    totalCarbonFootprint = streamingCarbon + cloudCarbon + deviceCarbon + internetCarbon + videoCallCarbon + gamingCarbon;

    return {
        totalCarbonFootprint: totalCarbonFootprint,
        streamingCarbon: streamingCarbon,
        cloudCarbon: cloudCarbon,
        deviceCarbon: deviceCarbon,
        internetCarbon: internetCarbon,
        videoCallCarbon: videoCallCarbon,
        gamingCarbon: gamingCarbon
    };
}
